sys_ws_operation.operation_script:
(function process( /*RESTAPIRequest*/ request, /*RESTAPIResponse*/ response) {
    var httpRequestUtils = new HttpRequestUtils();
    var profileService = new ProfileService();
    var logger = new Logger('profile/import');

    try {
        logger.debug('start fetching profiles');
        var profiles = profileService.getProfiles();
        var filteredProfiles = profileService.getFilteredProfiles(profiles);
    } catch (error) {
        logger.error("Can't get profiles: {0}", error.message);
        response.setStatus(500);
        response.setBody(["Can't get profiles"]);
		return;
    }

    try {
        logger.debug('Start saving profiles');
        profileService.saveProfiles(filteredProfiles);
    } catch (error) {
        logger.error("Can't save profiles: {0}", error.message);
        response.setStatus(500);
        response.setBody(["Can't save profiles"]);
		return;
    }

    response.setStatus(200);
    response.setBody({});
})(request, response);
